--  DDL for Procedure APPEND_ROW_TO_BANDWIDTH_CLOB
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."APPEND_ROW_TO_BANDWIDTH_CLOB" (
    p_xml             IN OUT CLOB,
    p_reference       IN VARCHAR2,
    p_product_name IN VARCHAR2,
    p_rating_property         IN VARCHAR2,
    p_package_code         IN VARCHAR2,
    p_effective_date   IN TIMESTAMP
) IS
    v_row CLOB;
BEGIN
    DBMS_LOB.CREATETEMPORARY(v_row, TRUE);

    DBMS_LOB.APPEND(v_row, '<Row>');
    DBMS_LOB.APPEND(v_row, make_cell_string(''));
    DBMS_LOB.APPEND(v_row, make_cell_string(''));
    DBMS_LOB.APPEND(v_row, make_cell_string('A'));
    DBMS_LOB.APPEND(v_row, make_cell_string('AGR_BRE_FR'));
    DBMS_LOB.APPEND(v_row, make_cell_string('Batelco National'));
    DBMS_LOB.APPEND(v_row, make_cell_string('Batelco'));
    DBMS_LOB.APPEND(v_row, make_cell_string(p_reference));

    --here is a conditionaly row depending on the product, there would be a product name
    DBMS_LOB.APPEND(v_row, make_cell_string(p_product_name));
    --here is a conditionaly row depending on the product, there would be a product rating property
    DBMS_LOB.APPEND(v_row, make_cell_string(p_rating_property));

    DBMS_LOB.APPEND(v_row, make_cell_string('BANDWIDTH'));
    DBMS_LOB.APPEND(v_row, make_cell_string(''));
    DBMS_LOB.APPEND(v_row, make_cell_string(''));

    --DATE the first date of the month like we did before 
    DBMS_LOB.APPEND(v_row, make_cell_datetime(p_effective_date, 's67'));


    DBMS_LOB.APPEND(v_row, make_cell_string(''));
    DBMS_LOB.APPEND(v_row, make_cell_string(''));

    -- the product text value -the value from the - BNET_PACK_CODE- column in siebel table
    DBMS_LOB.APPEND(v_row, make_cell_string(p_package_code));

    DBMS_LOB.APPEND(v_row, make_cell_string(''));
    DBMS_LOB.APPEND(v_row, '</Row>' || CHR(10));

    --ADD ROWS TO THE XML CLOB
    DBMS_LOB.APPEND(p_xml, v_row);

END;


