/
--------------------------------------------------------
--  DDL for Procedure GENERATE_SCENARIO1_STEP1
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."GENERATE_SCENARIO1_STEP1" (
    p_file_name OUT VARCHAR2,
    p_file_clob OUT CLOB
) IS

    v_xml CLOB;
    v_timestamp1 TIMESTAMP;
    v_timestamp2 TIMESTAMP;
    v_product    VARCHAR2(20);
BEGIN
    -- Step 1: create template
    generate_template_clob(v_xml);

    -- Step 2: loop through discrepancies
    FOR rec IN (
        SELECT *
        FROM Siebel_Table s
        WHERE s.BNET_REF IN (
            SELECT BNET_REF
            FROM Siebel_Table
            WHERE STATUS_CD = 'Active'
              AND RENTAL_PLAN NOT LIKE '%eFax%'
              AND BNET_PACK_CODE IS NOT NULL
              AND BNET_REF NOT LIKE '1182896926%'
              AND BNET_REF NOT LIKE '000%'
              AND BNET_REF NOT LIKE 'Skip%'
            MINUS
            SELECT DISTINCT r.BNET_REF
            FROM ROWB_Table r
            WHERE r.STATUS = 'Active'


        )

    )
    LOOP
        -- First timestamp: fixed far‑future date
        v_timestamp1 := TO_TIMESTAMP('2999-12-01 23:59:59.000',
                                     'YYYY-MM-DD HH24:MI:SS.FF3');

        -- Second timestamp: start of current billing month
        v_timestamp2 := TRUNC(SYSDATE, 'MM');

        -- Conditional product mapping
        IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
            v_product := 'WS_RES';
        ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
            v_product := 'WS_NRS';
        ELSE
            v_product := rec.BNET_PACK_CODE; -- fallback if neither keyword found
        END IF;

        -- Call your row‑append procedure with parameters
        append_row_to_clob(
            v_xml,
            rec.BNET_REF,          -- reference number
            v_timestamp1,          -- effective to
            v_product,           -- product/service
            v_timestamp2           -- effective from
        );
    END LOOP;

    -- Step 3: finalize
    finalize_xml_clob(v_xml);

    -- Step 4: save to file
   -- write_clob_to_file('SC1-STEP1.xml', v_xml);

   -- Step 4: return the file name and the file content
    p_file_name := 'SC1-STEP1.xml';
    p_file_clob := v_xml;

END;

