--------------------------------------------------------
--  DDL for Procedure GENERATE_SCENARIO1_STEP1_LOG
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."GENERATE_SCENARIO1_STEP1_LOG" (
    p_missing_customer OUT NUMBER,             -- OUT parameter for count
    p_file_name        OUT VARCHAR2,           -- OUT parameter for file name
    p_file_clob        OUT CLOB,               -- OUT parameter for file content
    p_config_id        IN  NUMBER,             -- configuration ID
    p_is_triggered     IN  BOOLEAN DEFAULT FALSE, -- automated/manual flag
    p_run_id           IN  NUMBER              -- reconciliation run ID
) IS
    v_xml CLOB;
    v_timestamp1 TIMESTAMP;
    v_timestamp2 TIMESTAMP;
    v_product    VARCHAR2(20);

    -- values fetched from "system_configuration"
    v_default_path      VARCHAR2(4000);
    v_ignore_conditions VARCHAR2(4000);
BEGIN
    p_missing_customer := 0;  -- initialize counter

    -- Step 0: fetch configuration row
    BEGIN
        SELECT default_file_path, ignore_conditions
        INTO v_default_path, v_ignore_conditions
        FROM "system_configuration"
        WHERE config_id = p_config_id;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            v_default_path := NULL;
            v_ignore_conditions := NULL;
    END;

    -- Step 1: create template
    generate_template_clob(v_xml);

    -- Step 2: loop through discrepancies
    FOR rec IN (
        SELECT *
        FROM Siebel_Table s
        WHERE s.BNET_REF IN (
            SELECT BNET_REF
            FROM Siebel_Table
            WHERE STATUS_CD = 'Active'
              AND RENTAL_PLAN NOT LIKE '%eFax%'
              AND BNET_PACK_CODE IS NOT NULL
              -- Apply ignore conditions if present
              AND (v_ignore_conditions IS NULL OR s.BNET_REF NOT LIKE v_ignore_conditions)
            MINUS
            SELECT DISTINCT r.BNET_REF
            FROM ROWB_Table r
            WHERE r.STATUS = 'Active'
        )
    )
    LOOP
        -- increment counter
        p_missing_customer := p_missing_customer + 1;

        -- First timestamp: fixed far‑future date
        v_timestamp1 := TO_TIMESTAMP('2999-12-01 23:59:59.000',
                                     'YYYY-MM-DD HH24:MI:SS.FF3');

        -- Second timestamp: start of current billing month
        v_timestamp2 := TRUNC(SYSDATE, 'MM');

        -- Conditional product mapping
        IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
            v_product := 'WS_RES';
        ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
            v_product := 'WS_NRS';
        ELSE
            v_product := rec.BNET_PACK_CODE; -- fallback if neither keyword found
        END IF;

        -- Call your row‑append procedure with parameters
        append_row_to_clob(
            v_xml,
            rec.BNET_REF,          -- reference number
            v_timestamp1,          -- effective to
            v_product,             -- product/service
            v_timestamp2           -- effective from
        );
    END LOOP;

    -- Step 3: finalize
    finalize_xml_clob(v_xml);

    -- Step 4: save to file only if condition met
    IF p_is_triggered AND v_default_path IS NOT NULL THEN
        write_clob_to_file(v_default_path, 'SC1-STEP1_log_' || p_run_id || '.xml', v_xml);

        -- Register generated file
        register_generated_file('SC1-STEP1_log_' || p_run_id || '.xml', v_default_path, p_run_id, 1);
    END IF;

    -- Step 5: return the file name and the file content
    p_file_name := 'SC1-STEP1_log_' || p_run_id || '.xml';
    p_file_clob := v_xml;

EXCEPTION
    WHEN OTHERS THEN
        -- Log the error against the run ID
        system_log_event(p_run_id, 'Scenario1 Step1 Log failed: ' || SQLERRM, 3);
        RAISE;
END;

