  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."GENERATE_SCENARIO2_UPDATE" (
    p_file_name OUT VARCHAR2,
    p_file_clob OUT CLOB
) IS
    v_xml        CLOB;
    v_timestamp1 TIMESTAMP;
    v_timestamp2 TIMESTAMP;
    v_product    VARCHAR2(20);
BEGIN
    -- Step 1: create template
    generate_template_clob(v_xml);

    -- Step 2: loop through Scenario Two discrepancies
    FOR rec IN (
        SELECT r.BNET_REF,
               s.BNET_PACK_CODE,
               s.DISCONNECT_DT,
               s.START_DT
        FROM ROWB_Table r
        LEFT JOIN Siebel_Table s
          ON r.BNET_REF = s.BNET_REF
        WHERE UPPER(r.STATUS) = 'ACTIVE'
          AND r.BNET_REF NOT LIKE '1182896926%'
          AND r.BNET_REF NOT LIKE '000%'
          AND r.BNET_REF NOT LIKE 'Skip%'
          AND r.BNET_REF IS NOT NULL
          AND r.BNET_REF NOT IN (
              SELECT s2.BNET_REF
              FROM Siebel_Table s2
              WHERE UPPER(s2.STATUS_CD) <> 'ACTIVE'
                AND s2.DISCONNECT_DT IS NOT NULL
                AND s2.RENTAL_PLAN NOT LIKE '%eFax%'
                AND s2.BNET_PACK_CODE IS NOT NULL
          )

    )
    LOOP
        -- Effective TO: normalize DISCONNECT_DT
        v_timestamp1 := normalize_date(rec.DISCONNECT_DT);

        -- Effective FROM: normalize START_DT
        v_timestamp2 := normalize_date(rec.START_DT);

        -- Conditional product mapping
        IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
            v_product := 'WS_RES';
        ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
            v_product := 'WS_NRS';
        ELSE
            v_product := rec.BNET_PACK_CODE; -- fallback
        END IF;

        -- Append row to CLOB
        append_row_to_clob(
            v_xml,
            rec.BNET_REF,     -- reference number
            v_timestamp1,     -- effective TO (disconnect date)
            v_product,        -- product/service
            v_timestamp2      -- effective FROM (start date)
        );
    END LOOP;

    -- Step 3: finalize
    finalize_xml_clob(v_xml);

    -- Step 4: save to file
    --write_clob_to_file('SC2-UPDATE.xml', v_xml);

    -- Step 4: return file name and content
    p_file_name := 'SC2-UPDATE.xml';
    p_file_clob := v_xml;


END;

