set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."GENERATE_SCENARIO3_MISMATCH" (
    p_file_name OUT VARCHAR2,
    p_file_clob OUT CLOB
) IS
    v_xml CLOB;
    v_timestamp TIMESTAMP;
    v_product_name    VARCHAR2(120);
    v_rating_property VARCHAR2(120);
BEGIN
    -- Step 1: create template
    generate_bandwidth_template_clob(v_xml);

    -- Step 2: loop through mismatched package discrepancies
    FOR rec IN (
    SELECT r.BNET_REF,
           s.BNET_PACK_CODE
    FROM ROWB_Table r
    JOIN Siebel_Table s
      ON r.BNET_REF = s.BNET_REF
    WHERE r.ROWB_PACKAGE <> s.BNET_PACK_CODE
      AND s.BNET_PACK_CODE IS NOT NULL
      AND r.ROWB_PACKAGE IS NOT NULL
      AND s.RENTAL_PLAN NOT LIKE '%eFax%'
      AND r.BNET_REF NOT LIKE '1182896926%'
      AND r.BNET_REF NOT LIKE '000%'
      AND r.BNET_REF NOT LIKE 'Skip%'
)
    LOOP
        -- Billing date (effective from): start of current billing month
        v_timestamp := TRUNC(SYSDATE, 'MM');

        -- Conditional product mapping based on Siebel pack code
        IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
            v_product_name := 'WS_RES Outpayment';
            v_rating_property := 'RP_WS_RS_O';
        ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
            v_product_name := 'WS_NRS Outpayment';
            v_rating_property := 'RP_WS_NS_O';
        ELSE
            v_product_name := rec.BNET_PACK_CODE; -- fallback
            v_rating_property := NULL;
        END IF;

        -- Append row to CLOB using Siebel pack code as the correct one
        append_row_to_bandwidth_clob(
            v_xml,
            rec.BNET_REF,        -- reference number
            v_product_name,      -- mapped product name
            v_rating_property,   -- rating property
            rec.BNET_PACK_CODE,  -- correct package from Siebel
            v_timestamp          -- billing date
        );
    END LOOP;

    -- Step 3: finalize
    finalize_xml_clob(v_xml);

    -- Step 4: save to file
    --write_clob_to_file('SC3-MISMATCH.xml', v_xml);

    -- Step 4: return file name and content
    p_file_name := 'SC3-MISMATCH.xml';
    p_file_clob := v_xml;

END;

