        html:Face="Arial" x:Family="Swiss"> Minimum override value.  MIN_OVERRIDE_VALUE (Type: Numeric, Length: 18, 6) </Font></ss:Data></Comment></Cell>
    <Cell ss:StyleID="s64"><Data ss:Type="String">Maximum Value Indicator</Data><Comment
      ss:Author="hercules"><ss:Data xmlns="http://www.w3.org/TR/REC-html40"><Font
        html:Face="Arial" x:Family="Swiss"> Determines if the product rating plan minimum value per charge should be enforced for this product service and if so - how it is enforced. Options: YES(Apply Rating Plan), NO(Do Not Apply), OVR(Apply Override).  APPLY_MAX_IND (Type: String, Length: 3) </Font></ss:Data></Comment></Cell>
    <Cell ss:StyleID="s65"><Data ss:Type="String">Max Override Value</Data><Comment
      ss:Author="hercules"><ss:Data xmlns="http://www.w3.org/TR/REC-html40"><Font
        html:Face="Arial" x:Family="Swiss"> Maximum override value.  MAX_OVERRIDE_VALUE (Type: Numeric, Length: 18, 6) </Font></ss:Data></Comment></Cell>
    <Cell ss:StyleID="s64"><Data ss:Type="String">% Shared</Data><Comment
      ss:Author="hercules"><ss:Data xmlns="http://www.w3.org/TR/REC-html40"><Font
        html:Face="Arial" x:Family="Swiss"> The percentage apportioned to the billable party in this product service when charges are shared.  SPLIT_PERCENTAGE (Type: Numeric, Length: 5, 2) </Font></ss:Data></Comment></Cell>
    <Cell ss:StyleID="s65"><Data ss:Type="String">Shared Charge Reference</Data><Comment
      ss:Author="hercules"><ss:Data xmlns="http://www.w3.org/TR/REC-html40"><Font
        html:Face="Arial" x:Family="Swiss"> Stores a reference to enable charges that are split between multiple billable parties to be referenced to each other.  SPLIT_REFERENCE (Type: String, Length: 30) </Font></ss:Data></Comment></Cell>
   </Row>
';

    DBMS_LOB.APPEND(p_xml, v_header );

END;


/
--------------------------------------------------------
--  DDL for Procedure GENERATE_XML_CLOB
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."GENERATE_XML_CLOB" (
    p_xml OUT CLOB
) IS
BEGIN
    p_xml := '<?xml version="1.0"?>' || CHR(10) ||
             '<RowbTable>' || CHR(10);

    FOR rec IN (
        SELECT *
        FROM rowb_table
        WHERE ROWNUM <= 10
    ) LOOP
        p_xml := p_xml ||
                 '  <RowbRow>' || CHR(10);

        p_xml := p_xml || '    <BNET_REF>' || rec.bnet_ref || '</BNET_REF>' || CHR(10);
        p_xml := p_xml || '    <ID>' || rec.id || '</ID>' || CHR(10);
        p_xml := p_xml || '    <OPERATOR_NAME>' || rec.operator_name || '</OPERATOR_NAME>' || CHR(10);
        p_xml := p_xml || '    <PRODUCT_CODE>' || rec.product_code || '</PRODUCT_CODE>' || CHR(10);
        p_xml := p_xml || '    <STATUS>' || rec.status || '</STATUS>' || CHR(10);
        p_xml := p_xml || '    <ORIGINAL_STATUS>' || rec.original_status || '</ORIGINAL_STATUS>' || CHR(10);
        p_xml := p_xml || '    <BILLING_END_DT>' || rec.billing_end_dt || '</BILLING_END_DT>' || CHR(10);
        p_xml := p_xml || '    <ROWB_PACKAGE>' || rec.rowb_package || '</ROWB_PACKAGE>' || CHR(10);

        p_xml := p_xml || '  </RowbRow>' || CHR(10);
    END LOOP;

    p_xml := p_xml || '</RowbTable>';
END;


/
--------------------------------------------------------
--  DDL for Procedure PURGE_RECONCILIATION_LOGS
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."PURGE_RECONCILIATION_LOGS" IS
    v_days_to_delete_auditlogs NUMBER;
    v_audit_deleted       NUMBER;
    v_file_deleted        NUMBER;
BEGIN
    -- Fetch days_to_delete_auditlogs from latest active configuration
    SELECT days_to_delete_auditlogs
    INTO v_days_to_delete_auditlogs
    FROM "system_configuration"
    WHERE is_active = 'Y'
    ORDER BY created_at DESC
    FETCH FIRST 1 ROWS ONLY;

    -- Skip deletion if days_to_delete_auditlogs is not configured
    IF v_days_to_delete_auditlogs IS NULL THEN
        RETURN;
    END IF;

    -- Delete old audit log entries
    DELETE FROM "system_log"
    WHERE created_at < SYSDATE - v_days_to_delete_auditlogs;

    v_audit_deleted := SQL%ROWCOUNT;

    -- Delete old file log entries
    DELETE FROM "generated_file"
    WHERE created_at < SYSDATE - v_days_to_delete_auditlogs;

    v_file_deleted := SQL%ROWCOUNT;

    COMMIT;

    -- Record purge action in system_log
    system_log_event(
        NULL,
        'Log purge: deleted logs older than ' || v_days_to_delete_auditlogs || ' days'
        || ' (audit_logs: ' || v_audit_deleted || ' rows, file_logs: ' || v_file_deleted || ' rows)',
        1
    );

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RAISE;
END;

/
--------------------------------------------------------
--  DDL for Procedure REGISTER_GENERATED_FILE
