--------------------------------------------------------
--  DDL for Procedure RUN_MAIN_RECONCILIATION
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."RUN_MAIN_RECONCILIATION" IS
    -- Variables to hold outputs from each scenario
    v_file1_name VARCHAR2(200);
    v_file1_clob CLOB;
    v_file2_name VARCHAR2(200);
    v_file2_clob CLOB;
    v_file3_name VARCHAR2(200);
    v_file3_clob CLOB;
    v_file4_name VARCHAR2(200);
    v_file4_clob CLOB;
BEGIN
    -- Scenario 1 Step 1
    GENERATE_SCENARIO1_STEP1(v_file1_name, v_file1_clob);

    -- Scenario 1 Step 2
    GENERATE_SCENARIO1_STEP2(v_file2_name, v_file2_clob);

    -- Scenario 2 Update
    GENERATE_SCENARIO2_UPDATE(v_file3_name, v_file3_clob);

    -- Scenario 3 Mismatch
    GENERATE_SCENARIO3_MISMATCH(v_file4_name, v_file4_clob);

    -- Send email with all four attachments
    SEND_EMAIL_WITH_CLOBS(
        p_sender      => 'noreply@test.local',
        p_recipient   => 'receiver@test.local',
        p_cc          => 'ccperson@test.local',
        p_subject     => 'Reconciliation Run Results',
        p_message     => 'Please find attached the reconciliation files generated for the process between Siebel and ROWB.<br><br>' ||
             'Each file corresponds to a specific scenario:<br>' ||
             '<ul>' ||
             '<li><b>SC1-Step1:</b> Missing records in ROWB compared to Siebel. [insert process]</li>' ||
             '<li><b>SC1-Step2:</b> Product linking in ROWB for new records in SC1-Step1. [insert process]</li>' ||
             '<li><b>SC2:</b> Package mismatches between Siebel and ROWB. [update process]</li>' ||
             '<li><b>SC3:</b> Billing discrepancies identified during reconciliation. [update process]</li>' ||
             '</ul>',
        p_file1_name  => v_file1_name,
        p_file1_clob  => v_file1_clob,
        p_file2_name  => v_file2_name,
        p_file2_clob  => v_file2_clob,
        p_file3_name  => v_file3_name,
        p_file3_clob  => v_file3_clob,
        p_file4_name  => v_file4_name,
        p_file4_clob  => v_file4_clob
    );
END;

/
--------------------------------------------------------
--  DDL for Procedure RUN_MAIN_RECONCILIATION_LOG
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."RUN_MAIN_RECONCILIATION_LOG" (
    p_is_triggered     IN  BOOLEAN DEFAULT FALSE, --set to true when called from scheduler, false when called manually
    p_triggered_by     IN  VARCHAR2 DEFAULT 'Manually',
    -- OUT parameters for manual runs
    p_out_file1_name   OUT VARCHAR2,
    p_out_file1_clob   OUT CLOB,
    p_out_file2_name   OUT VARCHAR2,
    p_out_file2_clob   OUT CLOB,
    p_out_file3_name   OUT VARCHAR2,
    p_out_file3_clob   OUT CLOB,
    p_out_file4_name   OUT VARCHAR2,
    p_out_file4_clob   OUT CLOB
) IS
    v_run_id NUMBER;
    v_config_id NUMBER;
    v_missing_customer NUMBER;
    v_missing_billing NUMBER;
    v_mismatch_count NUMBER;
    v_total_discrepancies NUMBER;
    v_total_records NUMBER;

    -- local file outputs
    v_file_name1 VARCHAR2(200);
    v_file_clob1 CLOB;
    v_file_name2 VARCHAR2(200);
    v_file_clob2 CLOB;
    v_file_name3 VARCHAR2(200);
    v_file_clob3 CLOB;
    v_file_name4 VARCHAR2(200);
    v_file_clob4 CLOB;

    -- email recipients
    v_recipients VARCHAR2(4000);
BEGIN
    -- Step 0: fetch latest active configuration
    SELECT config_id, email_recipients
    INTO v_config_id, v_recipients
    FROM "system_configuration"
    WHERE is_active = 'Y'
    ORDER BY created_at DESC
    FETCH FIRST 1 ROWS ONLY;

    -- Step 1: Insert run start
    REGISTER_RECONCILIATION_RUN(
        v_config_id,
        NULL,
        CASE WHEN p_is_triggered THEN 'Automatically' ELSE p_triggered_by END,
        CASE WHEN p_is_triggered THEN 1 ELSE 2 END,
        NULL,
        1,   -- Started
        v_run_id
    );
    system_log_event(v_run_id, 'Reconciliation run started', 1);

    -- Calculate total records processed (scope of run)
    SELECT COUNT(*) INTO v_total_records
    FROM (
        SELECT BNET_REF FROM Siebel_Table
        UNION ALL
        SELECT BNET_REF FROM ROWB_Table
    );

    -- Scenario 1 Step 1
    GENERATE_SCENARIO1_STEP1_LOG(
        v_missing_customer,
        v_file_name1,
        v_file_clob1,
        v_config_id,
        p_is_triggered,
        v_run_id
    );

    -- Scenario 1 Step 2
    GENERATE_SCENARIO1_STEP2_LOG(
        v_file_name2,
        v_file_clob2,
        v_config_id,
        p_is_triggered,
        v_run_id
    );

    -- Scenario 2 Update
    GENERATE_SCENARIO2_UPDATE_LOG(
        v_missing_billing,
        v_file_name3,
        v_file_clob3,
        v_config_id,
        p_is_triggered,
        v_run_id
    );

    -- Scenario 3 Mismatch
    GENERATE_SCENARIO3_MISMATCH_LOG(
        v_mismatch_count,
        v_file_name4,
        v_file_clob4,
        v_config_id,
        p_is_triggered,
        v_run_id
    );

    -- Discrepancies = sum of scenario counts
    v_total_discrepancies := v_missing_customer + v_missing_billing + v_mismatch_count;

    -- Insert summary row
    register_reconciliation_summary(
        v_total_records,
        v_total_discrepancies,
        v_mismatch_count,
        v_missing_customer,
        v_missing_billing,
        v_run_id
    );

    -- Step 2: Update run end (success)
    update_reconciliation_run(v_run_id, 'Completed');

    -- Step 3: Handle output (email when the process is triggered through scheduler)
    IF p_is_triggered = TRUE THEN
        IF v_recipients IS NOT NULL AND TRIM(v_recipients) IS NOT NULL THEN
            BEGIN
                -- Automatic run → send email with all four attachments
                SEND_EMAIL_WITH_CLOBS(
                    p_sender      => 'noreply@test.local',   -- static sender
                    p_recipient   => v_recipients,           -- fetched from configuration
                    p_cc          => 'ccperson@test.local',  -- static CC
                    p_subject     => 'Reconciliation Run Results',
                    p_message     => 'Please find attached the reconciliation files generated for the process between Siebel and ROWB.<br><br>' ||
                                     'Each file corresponds to a specific scenario:<br>' ||
                                     '<ul>' ||
                                     '<li><b>SC1-Step1:</b> Missing records in ROWB compared to Siebel. [insert process]</li>' ||
                                     '<li><b>SC1-Step2:</b> Product linking in ROWB for new records in SC1-Step1. [insert process]</li>' ||
                                     '<li><b>SC2:</b> Package mismatches between Siebel and ROWB. [update process]</li>' ||
                                     '<li><b>SC3:</b> Billing discrepancies identified during reconciliation. [update process]</li>' ||
                                     '</ul>',
                    p_file1_name  => v_file_name1,
                    p_file1_clob  => v_file_clob1,
                    p_file2_name  => v_file_name2,
                    p_file2_clob  => v_file_clob2,
                    p_file3_name  => v_file_name3,
                    p_file3_clob  => v_file_clob3,
                    p_file4_name  => v_file_name4,
                    p_file4_clob  => v_file_clob4
                );
                system_log_event(v_run_id, 'Email with reconciliation results sent successfully', 1);

                -- Update run with email status = SENT (1)
                update_reconciliation_run(v_run_id, 'Completed', NULL, 1);
            EXCEPTION
                WHEN OTHERS THEN
                    -- Email failed → update run with email status = FAILED (2)
                    update_reconciliation_run(v_run_id, 'Completed', SQLERRM, 2);
                    system_log_event(v_run_id, 'Email sending failed: ' || SQLERRM, 2);
            END;
        ELSE
            -- No recipients configured → skip email, log and mark as skipped
            system_log_event(v_run_id, 'Email skipped: no recipients configured in active configuration', 2);
            update_reconciliation_run(v_run_id, 'Completed', NULL, NULL);
        END IF;
    ELSE
        -- Manual run → return files in OUT parameters
        p_out_file1_name := v_file_name1;
        p_out_file1_clob := v_file_clob1;
        p_out_file2_name := v_file_name2;
        p_out_file2_clob := v_file_clob2;
        p_out_file3_name := v_file_name3;
        p_out_file3_clob := v_file_clob3;
        p_out_file4_name := v_file_name4;
        p_out_file4_clob := v_file_clob4;
        system_log_event(v_run_id, 'Files returned to caller for manual run', 1);

        -- Manual run → leave email_status_id NULL
        update_reconciliation_run(v_run_id, 'Completed', NULL, NULL);
    END IF;

EXCEPTION
    WHEN OTHERS THEN
        -- Step 4: Update run end (failure)
        update_reconciliation_run(v_run_id, 'Failed', SQLERRM, 2); -- mark email status as failed if relevant
        system_log_event(v_run_id, 'Reconciliation run failed: ' || SQLERRM, 3);
        RAISE;
END;

/
--------------------------------------------------------
--  DDL for Procedure SEND_EMAIL_WITH_CLOBS
--------------------------------------------------------
set define off;

  CREATE OR REPLACE EDITIONABLE PROCEDURE "BILLING_MOCK"."SEND_EMAIL_WITH_CLOBS" (
    p_sender      IN VARCHAR2,
    p_recipient   IN VARCHAR2,
    p_cc          IN VARCHAR2,
    p_subject     IN VARCHAR2,
    p_message     IN VARCHAR2,
    p_file1_name  IN VARCHAR2,
    p_file1_clob  IN CLOB,
    p_file2_name  IN VARCHAR2,
    p_file2_clob  IN CLOB,
    p_file3_name  IN VARCHAR2,
    p_file3_clob  IN CLOB,
    p_file4_name  IN VARCHAR2,
    p_file4_clob  IN CLOB
) IS
    conn     UTL_SMTP.connection;
    boundary CONSTANT VARCHAR2(50) := '----=_NextPart_001';

    -- Helper to stream CLOB safely in chunks
    PROCEDURE stream_clob_as_attachment(
        p_name     IN VARCHAR2,
        p_clob     IN CLOB
    ) IS
        v_pos    INTEGER := 1;
        v_length INTEGER;
        v_chunk  VARCHAR2(10900); -- safe chunk size
    BEGIN
        IF p_clob IS NOT NULL THEN
            -- Write attachment headers
            UTL_SMTP.write_data(conn,
                '--' || boundary || CHR(13) || CHR(10) ||
                'Content-Type: text/xml; name="' || p_name || '"' || CHR(13) || CHR(10) ||
                'Content-Disposition: attachment; filename="' || p_name || '"' || CHR(13) || CHR(10) ||
                CHR(13) || CHR(10)
            );

            -- Stream CLOB in chunks
            v_length := DBMS_LOB.getlength(p_clob);
            WHILE v_pos <= v_length LOOP
                v_chunk := DBMS_LOB.substr(p_clob, 10900, v_pos);
                UTL_SMTP.write_data(conn, v_chunk);
                v_pos := v_pos + 10900;
            END LOOP;

            UTL_SMTP.write_data(conn, CHR(13) || CHR(10));
        END IF;
    END;
BEGIN
    -- Connect to smtp4dev (localhost:25)
    conn := UTL_SMTP.open_connection('localhost', 25);
    UTL_SMTP.helo(conn, 'localhost');
    UTL_SMTP.mail(conn, p_sender);
    UTL_SMTP.rcpt(conn, p_recipient);
    IF p_cc IS NOT NULL THEN
        UTL_SMTP.rcpt(conn, p_cc);
    END IF;

    -- Start email headers
    UTL_SMTP.open_data(conn);
    UTL_SMTP.write_data(conn,
        'From: ' || p_sender || CHR(13) || CHR(10) ||
        'To: ' || p_recipient || CHR(13) || CHR(10) ||
        'Cc: ' || p_cc || CHR(13) || CHR(10) ||
        'Subject: ' || p_subject || CHR(13) || CHR(10) ||
        'MIME-Version: 1.0' || CHR(13) || CHR(10) ||
        'Content-Type: multipart/mixed; boundary="' || boundary || '"' || CHR(13) || CHR(10) ||
        CHR(13) || CHR(10)
    );

    -- Body
    UTL_SMTP.write_data(conn,
        '--' || boundary || CHR(13) || CHR(10) ||
        'Content-Type: text/plain' || CHR(13) || CHR(10) ||
        CHR(13) || CHR(10) ||
        p_message || CHR(13) || CHR(10)
    );

    -- Attachments
    stream_clob_as_attachment(p_file1_name, p_file1_clob);
    stream_clob_as_attachment(p_file2_name, p_file2_clob);
    stream_clob_as_attachment(p_file3_name, p_file3_clob);
    stream_clob_as_attachment(p_file4_name, p_file4_clob);

    -- End boundary
    UTL_SMTP.write_data(conn, '--' || boundary || '--' || CHR(13) || CHR(10));

    UTL_SMTP.close_data(conn);
    UTL_SMTP.quit(conn);
END;

