  CREATE OR REPLACE EDITIONABLE PACKAGE "BILLING_MOCK"."RECONCILIATION_PACKAGE" AS

    -- ----------------------------------------------------------------
    -- Public procedures (externally callable)
    -- ----------------------------------------------------------------
    PROCEDURE RUN_MAIN_RECONCILIATION;

    PROCEDURE GENERATE_SCENARIO1_STEP1  (p_file_name OUT VARCHAR2, p_file_clob OUT CLOB);
    PROCEDURE GENERATE_SCENARIO1_STEP2  (p_file_name OUT VARCHAR2, p_file_clob OUT CLOB);
    PROCEDURE GENERATE_SCENARIO2_UPDATE (p_file_name OUT VARCHAR2, p_file_clob OUT CLOB);
    PROCEDURE GENERATE_SCENARIO3_MISMATCH (p_file_name OUT VARCHAR2, p_file_clob OUT CLOB);

    PROCEDURE SEND_EMAIL_WITH_CLOBS (
        p_sender     IN VARCHAR2,
        p_recipient  IN VARCHAR2,
        p_cc         IN VARCHAR2,
        p_subject    IN VARCHAR2,
        p_message    IN VARCHAR2,
        p_file1_name IN VARCHAR2,
        p_file1_clob IN CLOB,
        p_file2_name IN VARCHAR2,
        p_file2_clob IN CLOB,
        p_file3_name IN VARCHAR2,
        p_file3_clob IN CLOB,
        p_file4_name IN VARCHAR2,
        p_file4_clob IN CLOB
    );

END RECONCILIATION_PACKAGE;

