  CREATE OR REPLACE EDITIONABLE PACKAGE BODY "BILLING_MOCK"."RECONCILIATION_LOG_PACKAGE" AS

    -- ================================================================
    --  FORWARD DECLARATIONS FOR PRIVATE SUBPROGRAMS
    -- ================================================================

    -- Helper functions
    FUNCTION  ESCAPE_XML               (p_text     IN VARCHAR2)                        RETURN VARCHAR2;
    FUNCTION  MAKE_CELL_DATETIME       (p_val      IN TIMESTAMP, p_style_id IN VARCHAR2) RETURN VARCHAR2;
    FUNCTION  MAKE_CELL_STRING         (p_val      IN VARCHAR2)                        RETURN VARCHAR2;
    FUNCTION  MAKE_CELL_NUMBER         (p_val      IN NUMBER)                          RETURN VARCHAR2;
    FUNCTION  NORMALIZE_DATE           (p_val      IN VARCHAR2)                        RETURN TIMESTAMP;

    -- Logging / registration
    PROCEDURE SYSTEM_LOG_EVENT         (p_run_id  IN NUMBER, p_message IN VARCHAR2, p_log_level IN NUMBER DEFAULT 1);
    PROCEDURE WRITE_CLOB_TO_FILE       (p_directory IN VARCHAR2, p_filename IN VARCHAR2, p_content IN CLOB);
    PROCEDURE REGISTER_GENERATED_FILE  (p_file_name IN VARCHAR2, p_server_file_path IN VARCHAR2, p_run_id IN NUMBER, p_file_type_id IN NUMBER DEFAULT 5);
    PROCEDURE REGISTER_RECONCILIATION_RUN (
        p_config_id    IN  NUMBER    DEFAULT NULL,
        p_error_msg    IN  VARCHAR2  DEFAULT NULL,
        p_triggered_by IN  VARCHAR2  DEFAULT 'Automatically',
        p_delivery_id  IN  NUMBER    DEFAULT 1,
        p_email_status IN  NUMBER    DEFAULT NULL,
        p_run_status   IN  NUMBER    DEFAULT 1,
        p_run_id       OUT NUMBER
    );
    PROCEDURE REGISTER_RECONCILIATION_SUMMARY (
        p_total_records       IN NUMBER DEFAULT 0,
        p_total_discrepancies IN NUMBER DEFAULT 0,
        p_mismatch_count      IN NUMBER DEFAULT 0,
        p_missing_customer    IN NUMBER DEFAULT 0,
        p_missing_billing     IN NUMBER DEFAULT 0,
        p_run_id              IN NUMBER
    );
    PROCEDURE UPDATE_RECONCILIATION_RUN (
        p_run_id          IN NUMBER,
        p_status          IN VARCHAR2,
        p_error_msg       IN VARCHAR2 DEFAULT NULL,
        p_email_status_id IN NUMBER   DEFAULT NULL
    );

    -- XML template builders
    PROCEDURE GENERATE_TEMPLATE_CLOB           (p_xml OUT CLOB);
    PROCEDURE GENERATE_BANDWIDTH_TEMPLATE_CLOB (p_xml OUT CLOB);

    -- XML row appenders
    PROCEDURE APPEND_ROW_TO_CLOB (
        p_xml             IN OUT CLOB,
        p_reference       IN     VARCHAR2,
        p_completion_date IN     TIMESTAMP,
        p_product         IN     VARCHAR2,
        p_starting_from   IN     TIMESTAMP
    );
    PROCEDURE APPEND_ROW_TO_BANDWIDTH_CLOB (
        p_xml             IN OUT CLOB,
        p_reference       IN     VARCHAR2,
        p_product_name    IN     VARCHAR2,
        p_rating_property IN     VARCHAR2,
        p_package_code    IN     VARCHAR2,
        p_effective_date  IN     TIMESTAMP
    );

    -- XML finalizer
    PROCEDURE FINALIZE_XML_CLOB (p_xml IN OUT CLOB);


    -- ================================================================
    --  PRIVATE IMPLEMENTATIONS
    -- ================================================================

    -- ----------------------------------------------------------------
    --  ESCAPE_XML
    -- ----------------------------------------------------------------
    FUNCTION ESCAPE_XML (p_text IN VARCHAR2) RETURN VARCHAR2 IS
    BEGIN
        RETURN REPLACE(
                 REPLACE(
                   REPLACE(
                     REPLACE(p_text, '&', '&amp;'),
                   '<', '&lt;'),
                 '>', '&gt;'),
               '"', '&quot;');
    END ESCAPE_XML;

    -- ----------------------------------------------------------------
    --  MAKE_CELL_DATETIME
    -- ----------------------------------------------------------------
    FUNCTION MAKE_CELL_DATETIME (
        p_val      TIMESTAMP,
        p_style_id VARCHAR2
    ) RETURN VARCHAR2 IS
    BEGIN
        RETURN '<Cell ss:StyleID="' || p_style_id || '"><Data ss:Type="DateTime">' ||
               TO_CHAR(p_val, 'YYYY-MM-DD"T"HH24:MI:SS.FF3') ||
               '</Data></Cell>';
    END MAKE_CELL_DATETIME;

    -- ----------------------------------------------------------------
    --  MAKE_CELL_STRING
    -- ----------------------------------------------------------------
    FUNCTION MAKE_CELL_STRING (p_val VARCHAR2) RETURN VARCHAR2 IS
    BEGIN
        RETURN '<Cell><Data ss:Type="String">' || ESCAPE_XML(p_val) || '</Data></Cell>';
    END MAKE_CELL_STRING;

    -- ----------------------------------------------------------------
    --  MAKE_CELL_NUMBER
    -- ----------------------------------------------------------------
    FUNCTION MAKE_CELL_NUMBER (p_val NUMBER) RETURN VARCHAR2 IS
    BEGIN
        RETURN '<Cell><Data ss:Type="Number">' || p_val || '</Data></Cell>';
    END MAKE_CELL_NUMBER;

    -- ----------------------------------------------------------------
    --  NORMALIZE_DATE
    -- ----------------------------------------------------------------
    FUNCTION NORMALIZE_DATE (p_val VARCHAR2) RETURN TIMESTAMP IS
        v_ts TIMESTAMP;
    BEGIN
        BEGIN
            v_ts := TO_TIMESTAMP(p_val, 'MM/DD/YYYY HH24:MI');
            RETURN v_ts;
        EXCEPTION WHEN OTHERS THEN NULL;
        END;

        BEGIN
            v_ts := TO_TIMESTAMP(p_val, 'MM/DD/YYYY');
            RETURN v_ts;
        EXCEPTION WHEN OTHERS THEN NULL;
        END;

        RETURN NULL;
    END NORMALIZE_DATE;

    -- ----------------------------------------------------------------
    --  SYSTEM_LOG_EVENT
    -- ----------------------------------------------------------------
    PROCEDURE SYSTEM_LOG_EVENT (
        p_run_id    IN NUMBER,
        p_message   IN VARCHAR2,
        p_log_level IN NUMBER DEFAULT 1
    ) IS
    BEGIN
            log_message,
            created_at,
            log_level_id,
            run_id
        )
        VALUES (
            p_message,
            SYSTIMESTAMP,
            p_log_level,
            p_run_id
        );
        COMMIT;
    END SYSTEM_LOG_EVENT;

    -- ----------------------------------------------------------------
    --  WRITE_CLOB_TO_FILE
    -- ----------------------------------------------------------------
    PROCEDURE WRITE_CLOB_TO_FILE (
        p_directory IN VARCHAR2,
        p_filename  IN VARCHAR2,
        p_content   IN CLOB
    ) IS
        f          UTL_FILE.FILE_TYPE;
        v_buffer   VARCHAR2(32767);
        v_pos      INTEGER := 1;
        v_length   INTEGER;
        v_dir_path VARCHAR2(4000);
    BEGIN
        -- Verify the Oracle directory object exists and is accessible
        BEGIN
            SELECT directory_path
            INTO   v_dir_path
            FROM   all_directories
            WHERE  directory_name = UPPER(p_directory);
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                RAISE_APPLICATION_ERROR(-20001,
                    'Directory object does not exist or is not accessible: ' || p_directory);
        END;

        v_length := DBMS_LOB.GETLENGTH(p_content);
        f := UTL_FILE.FOPEN(p_directory, p_filename, 'W', 32767);
        WHILE v_pos <= v_length LOOP
            v_buffer := DBMS_LOB.SUBSTR(p_content, 10900, v_pos);
            UTL_FILE.PUT(f, v_buffer);
            UTL_FILE.FFLUSH(f);
            v_pos := v_pos + 10900;
        END LOOP;
        UTL_FILE.FCLOSE(f);
    EXCEPTION
        WHEN OTHERS THEN
            IF UTL_FILE.IS_OPEN(f) THEN
                UTL_FILE.FCLOSE(f);
            END IF;
            RAISE;
    END WRITE_CLOB_TO_FILE;

    -- ----------------------------------------------------------------
    --  REGISTER_GENERATED_FILE
    -- ----------------------------------------------------------------
    PROCEDURE REGISTER_GENERATED_FILE (
        p_file_name        IN VARCHAR2,
        p_server_file_path IN VARCHAR2,
        p_run_id           IN NUMBER,
        p_file_type_id     IN NUMBER DEFAULT 5
    ) IS
    BEGIN
            file_name,
            server_file_path,
            created_at,
            run_id,
            file_type_id
        )
        VALUES (
            p_file_name,
            p_server_file_path,
            SYSTIMESTAMP,
            p_run_id,
            p_file_type_id
        );
        COMMIT;
    END REGISTER_GENERATED_FILE;

    -- ----------------------------------------------------------------
    --  REGISTER_RECONCILIATION_RUN
    -- ----------------------------------------------------------------
    PROCEDURE REGISTER_RECONCILIATION_RUN (
        p_config_id    IN  NUMBER   DEFAULT NULL,
        p_error_msg    IN  VARCHAR2 DEFAULT NULL,
        p_triggered_by IN  VARCHAR2 DEFAULT 'Automatically',
        p_delivery_id  IN  NUMBER   DEFAULT 1,
        p_email_status IN  NUMBER   DEFAULT NULL,
        p_run_status   IN  NUMBER   DEFAULT 1,
        p_run_id       OUT NUMBER
    ) IS
    BEGIN
            run_date,
            config_id,
            error_message,
            triggered_by,
            delivery_method_id,
            email_status_id,
            run_status_id
        )
        VALUES (
            SYSTIMESTAMP,
            p_config_id,
            p_error_msg,
            p_triggered_by,
            p_delivery_id,
            p_email_status,
            p_run_status
        )
        RETURNING run_id INTO p_run_id;

        COMMIT;
    END REGISTER_RECONCILIATION_RUN;

    -- ----------------------------------------------------------------
    --  REGISTER_RECONCILIATION_SUMMARY
    -- ----------------------------------------------------------------
    PROCEDURE REGISTER_RECONCILIATION_SUMMARY (
        p_total_records       IN NUMBER DEFAULT 0,
        p_total_discrepancies IN NUMBER DEFAULT 0,
        p_mismatch_count      IN NUMBER DEFAULT 0,
        p_missing_customer    IN NUMBER DEFAULT 0,
        p_missing_billing     IN NUMBER DEFAULT 0,
        p_run_id              IN NUMBER
    ) IS
    BEGIN
            total_records_processed,
            total_discrepancies,
            mismatch_count,
            missing_in_customer_count,
            missing_in_billing_count,
            created_at,
            run_id
        )
        VALUES (
            p_total_records,
            p_total_discrepancies,
            p_mismatch_count,
            p_missing_customer,
            p_missing_billing,
            SYSTIMESTAMP,
            p_run_id
        );
        COMMIT;
    END REGISTER_RECONCILIATION_SUMMARY;

    -- ----------------------------------------------------------------
    --  UPDATE_RECONCILIATION_RUN
    -- ----------------------------------------------------------------
    PROCEDURE UPDATE_RECONCILIATION_RUN (
        p_run_id          IN NUMBER,
        p_status          IN VARCHAR2,
        p_error_msg       IN VARCHAR2 DEFAULT NULL,
        p_email_status_id IN NUMBER   DEFAULT NULL
    ) IS
        v_status_id NUMBER;
    BEGIN
        SELECT run_status_id
        INTO v_status_id
        FROM "BILLING_MOCK"."run_status"
        WHERE UPPER(run_status) = UPPER(p_status);

        UPDATE "BILLING_MOCK"."reconciliation_run"
        SET run_status_id   = v_status_id,
            error_message   = p_error_msg,
            email_status_id = COALESCE(p_email_status_id, email_status_id)
        WHERE run_id = p_run_id;

        COMMIT;
    EXCEPTION
        WHEN NO_DATA_FOUND THEN
            RAISE_APPLICATION_ERROR(-20001, 'Invalid status string: ' || p_status);
    END UPDATE_RECONCILIATION_RUN;

