    -- ----------------------------------------------------------------
    --  GENERATE_SCENARIO1_STEP1_LOG
    -- ----------------------------------------------------------------
    PROCEDURE GENERATE_SCENARIO1_STEP1_LOG (
        p_missing_customer OUT NUMBER,
        p_file_name        OUT VARCHAR2,
        p_file_clob        OUT CLOB,
        p_config_id        IN  NUMBER,
        p_is_triggered     IN  BOOLEAN DEFAULT FALSE,
        p_run_id           IN  NUMBER
    ) IS
        v_xml               CLOB;
        v_timestamp1        TIMESTAMP;
        v_timestamp2        TIMESTAMP;
        v_product           VARCHAR2(20);
        v_default_path      VARCHAR2(4000);
        v_ignore_conditions VARCHAR2(4000);
    BEGIN
        p_missing_customer := 0;

        -- Fetch configuration row
        BEGIN
            SELECT default_file_path, ignore_conditions
            INTO v_default_path, v_ignore_conditions
            FROM "system_configuration"
            WHERE config_id = p_config_id;
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                v_default_path      := NULL;
                v_ignore_conditions := NULL;
        END;

        GENERATE_TEMPLATE_CLOB(v_xml);

        FOR rec IN (
            SELECT *
            FROM Siebel_Table s
            WHERE s.BNET_REF IN (
                SELECT BNET_REF
                FROM Siebel_Table
                WHERE STATUS_CD = 'Active'
                  AND RENTAL_PLAN NOT LIKE '%eFax%'
                  AND BNET_PACK_CODE IS NOT NULL
                  AND (v_ignore_conditions IS NULL OR s.BNET_REF NOT LIKE v_ignore_conditions)
                MINUS
                SELECT DISTINCT r.BNET_REF
                FROM ROWB_Table r
                WHERE r.STATUS = 'Active'
            )
        )
        LOOP
            p_missing_customer := p_missing_customer + 1;

            v_timestamp1 := TO_TIMESTAMP('2999-12-01 23:59:59.000', 'YYYY-MM-DD HH24:MI:SS.FF3');
            v_timestamp2 := TRUNC(SYSDATE, 'MM');

            IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
                v_product := 'WS_RES';
            ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
                v_product := 'WS_NRS';
            ELSE
                v_product := rec.BNET_PACK_CODE;
            END IF;

            APPEND_ROW_TO_CLOB(v_xml, rec.BNET_REF, v_timestamp1, v_product, v_timestamp2);
        END LOOP;

        FINALIZE_XML_CLOB(v_xml);

        IF v_default_path IS NOT NULL THEN
            WRITE_CLOB_TO_FILE(v_default_path, 'SC1-STEP1_log_' || p_run_id || '.xml', v_xml);
            REGISTER_GENERATED_FILE('SC1-STEP1_log_' || p_run_id || '.xml', v_default_path, p_run_id, 1);
        END IF;

        p_file_name := 'SC1-STEP1_log_' || p_run_id || '.xml';
        p_file_clob := v_xml;

    EXCEPTION
        WHEN OTHERS THEN
            SYSTEM_LOG_EVENT(p_run_id, 'Scenario1 Step1 Log failed: ' || SQLERRM, 3);
            RAISE;
    END GENERATE_SCENARIO1_STEP1_LOG;

    -- ----------------------------------------------------------------
    --  GENERATE_SCENARIO1_STEP2_LOG
    -- ----------------------------------------------------------------
    PROCEDURE GENERATE_SCENARIO1_STEP2_LOG (
        p_file_name    OUT VARCHAR2,
        p_file_clob    OUT CLOB,
        p_config_id    IN  NUMBER,
        p_is_triggered IN  BOOLEAN DEFAULT FALSE,
        p_run_id       IN  NUMBER
    ) IS
        v_xml               CLOB;
        v_timestamp         TIMESTAMP;
        v_product_name      VARCHAR2(120);
        v_rating_property   VARCHAR2(120);
        v_default_path      VARCHAR2(4000);
        v_ignore_conditions VARCHAR2(4000);
    BEGIN
        BEGIN
            SELECT default_file_path, ignore_conditions
            INTO v_default_path, v_ignore_conditions
            FROM "system_configuration"
            WHERE config_id = p_config_id;
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                v_default_path      := NULL;
                v_ignore_conditions := NULL;
        END;

        GENERATE_BANDWIDTH_TEMPLATE_CLOB(v_xml);

        FOR rec IN (
            SELECT *
            FROM Siebel_Table s
            WHERE s.BNET_REF IN (
                SELECT BNET_REF
                FROM Siebel_Table
                WHERE STATUS_CD = 'Active'
                  AND RENTAL_PLAN NOT LIKE '%eFax%'
                  AND BNET_PACK_CODE IS NOT NULL
                  AND (v_ignore_conditions IS NULL OR s.BNET_REF NOT LIKE v_ignore_conditions)
                MINUS
                SELECT DISTINCT r.BNET_REF
                FROM ROWB_Table r
                WHERE r.STATUS = 'Active'
            )
        )
        LOOP
            v_timestamp := TRUNC(SYSDATE, 'MM');

            IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
                v_product_name    := 'WS_RES Outpayment';
                v_rating_property := 'RP_WS_RS_O';
            ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
                v_product_name    := 'WS_NRS Outpayment';
                v_rating_property := 'RP_WS_NS_O';
            ELSE
                v_product_name    := rec.BNET_PACK_CODE;
                v_rating_property := NULL;
            END IF;

            APPEND_ROW_TO_BANDWIDTH_CLOB(
                v_xml,
                rec.BNET_REF,
                v_product_name,
                v_rating_property,
                rec.BNET_PACK_CODE,
                v_timestamp
            );
        END LOOP;

        FINALIZE_XML_CLOB(v_xml);

        IF v_default_path IS NOT NULL THEN
            WRITE_CLOB_TO_FILE(v_default_path, 'SC1-STEP2_log_' || p_run_id || '.xml', v_xml);
            REGISTER_GENERATED_FILE('SC1-STEP2_log_' || p_run_id || '.xml', v_default_path, p_run_id, 2);
        END IF;

        p_file_name := 'SC1-STEP2_log_' || p_run_id || '.xml';
        p_file_clob := v_xml;

    EXCEPTION
        WHEN OTHERS THEN
            SYSTEM_LOG_EVENT(p_run_id, 'Scenario1 Step2 Log failed: ' || SQLERRM, 3);
            RAISE;
    END GENERATE_SCENARIO1_STEP2_LOG;

    -- ----------------------------------------------------------------
    --  GENERATE_SCENARIO2_UPDATE_LOG
    -- ----------------------------------------------------------------
    PROCEDURE GENERATE_SCENARIO2_UPDATE_LOG (
        p_missing_billing OUT NUMBER,
        p_file_name       OUT VARCHAR2,
        p_file_clob       OUT CLOB,
        p_config_id       IN  NUMBER,
        p_is_triggered    IN  BOOLEAN DEFAULT FALSE,
        p_run_id          IN  NUMBER
    ) IS
        v_xml               CLOB;
        v_timestamp1        TIMESTAMP;
        v_timestamp2        TIMESTAMP;
        v_product           VARCHAR2(20);
        v_default_path      VARCHAR2(4000);
        v_ignore_conditions VARCHAR2(4000);
    BEGIN
        p_missing_billing := 0;

        BEGIN
            SELECT default_file_path, ignore_conditions
            INTO v_default_path, v_ignore_conditions
            FROM "system_configuration"
            WHERE config_id = p_config_id;
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                v_default_path      := NULL;
                v_ignore_conditions := NULL;
        END;

        GENERATE_TEMPLATE_CLOB(v_xml);

        FOR rec IN (
            SELECT r.BNET_REF,
                   s.BNET_PACK_CODE,
                   s.DISCONNECT_DT,
                   s.START_DT
            FROM ROWB_Table r
            LEFT JOIN Siebel_Table s ON r.BNET_REF = s.BNET_REF
            WHERE UPPER(r.STATUS) = 'ACTIVE'
              AND (v_ignore_conditions IS NULL OR r.BNET_REF NOT LIKE v_ignore_conditions)
              AND r.BNET_REF NOT LIKE '1182896926%'
              AND r.BNET_REF NOT LIKE '000%'
              AND r.BNET_REF NOT LIKE 'Skip%'
              AND r.BNET_REF IS NOT NULL
              AND r.BNET_REF NOT IN (
                  SELECT s2.BNET_REF
                  FROM Siebel_Table s2
                  WHERE UPPER(s2.STATUS_CD) <> 'ACTIVE'
                    AND s2.DISCONNECT_DT IS NOT NULL
                    AND s2.RENTAL_PLAN NOT LIKE '%eFax%'
                    AND s2.BNET_PACK_CODE IS NOT NULL
              )
        )
        LOOP
            p_missing_billing := p_missing_billing + 1;

            v_timestamp1 := NORMALIZE_DATE(rec.DISCONNECT_DT);
            v_timestamp2 := NORMALIZE_DATE(rec.START_DT);

            IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
                v_product := 'WS_RES';
            ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
                v_product := 'WS_NRS';
            ELSE
                v_product := rec.BNET_PACK_CODE;
            END IF;

            APPEND_ROW_TO_CLOB(v_xml, rec.BNET_REF, v_timestamp1, v_product, v_timestamp2);
        END LOOP;

        FINALIZE_XML_CLOB(v_xml);

        IF v_default_path IS NOT NULL THEN
            WRITE_CLOB_TO_FILE(v_default_path, 'SC2_UPDATE_log_' || p_run_id || '.xml', v_xml);
            REGISTER_GENERATED_FILE('SC2_UPDATE_log_' || p_run_id || '.xml', v_default_path, p_run_id, 2);
        END IF;

        p_file_name := 'SC2_UPDATE_log_' || p_run_id || '.xml';
        p_file_clob := v_xml;

    EXCEPTION
        WHEN OTHERS THEN
            SYSTEM_LOG_EVENT(p_run_id, 'Scenario2 Update failed: ' || SQLERRM, 3);
            RAISE;
    END GENERATE_SCENARIO2_UPDATE_LOG;

    -- ----------------------------------------------------------------
    --  GENERATE_SCENARIO3_MISMATCH_LOG
    -- ----------------------------------------------------------------
    PROCEDURE GENERATE_SCENARIO3_MISMATCH_LOG (
        p_mismatch_count OUT NUMBER,
        p_file_name      OUT VARCHAR2,
        p_file_clob      OUT CLOB,
        p_config_id      IN  NUMBER,
        p_is_triggered   IN  BOOLEAN DEFAULT FALSE,
        p_run_id         IN  NUMBER
    ) IS
        v_xml               CLOB;
        v_timestamp         TIMESTAMP;
        v_product_name      VARCHAR2(120);
        v_rating_property   VARCHAR2(120);
        v_default_path      VARCHAR2(4000);
        v_ignore_conditions VARCHAR2(4000);
    BEGIN
        p_mismatch_count := 0;

        BEGIN
            SELECT default_file_path, ignore_conditions
            INTO v_default_path, v_ignore_conditions
            FROM "system_configuration"
            WHERE config_id = p_config_id;
        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                v_default_path      := NULL;
                v_ignore_conditions := NULL;
        END;

        GENERATE_BANDWIDTH_TEMPLATE_CLOB(v_xml);

        FOR rec IN (
            SELECT r.BNET_REF,
                   s.BNET_PACK_CODE
            FROM ROWB_Table r
            JOIN Siebel_Table s ON r.BNET_REF = s.BNET_REF
            WHERE r.ROWB_PACKAGE <> s.BNET_PACK_CODE
              AND s.BNET_PACK_CODE IS NOT NULL
              AND r.ROWB_PACKAGE IS NOT NULL
              AND s.RENTAL_PLAN NOT LIKE '%eFax%'
              AND (v_ignore_conditions IS NULL OR r.BNET_REF NOT LIKE v_ignore_conditions)
              AND r.BNET_REF NOT LIKE '1182896926%'
              AND r.BNET_REF NOT LIKE '000%'
              AND r.BNET_REF NOT LIKE 'Skip%'
        )
        LOOP
            p_mismatch_count := p_mismatch_count + 1;

            v_timestamp := TRUNC(SYSDATE, 'MM');

            IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
                v_product_name    := 'WS_RES Outpayment';
                v_rating_property := 'RP_WS_RS_O';
            ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
                v_product_name    := 'WS_NRS Outpayment';
                v_rating_property := 'RP_WS_NS_O';
            ELSE
                v_product_name    := rec.BNET_PACK_CODE;
                v_rating_property := NULL;
            END IF;

            APPEND_ROW_TO_BANDWIDTH_CLOB(
                v_xml,
                rec.BNET_REF,
                v_product_name,
                v_rating_property,
                rec.BNET_PACK_CODE,
                v_timestamp
            );
        END LOOP;

        FINALIZE_XML_CLOB(v_xml);

        IF v_default_path IS NOT NULL THEN
            WRITE_CLOB_TO_FILE(v_default_path, 'SC3-MISMATCH_log_' || p_run_id || '.xml', v_xml);
            REGISTER_GENERATED_FILE('SC3-MISMATCH_log_' || p_run_id || '.xml', v_default_path, p_run_id, 3);
        END IF;

        p_file_name := 'SC3-MISMATCH_log_' || p_run_id || '.xml';
        p_file_clob := v_xml;

    EXCEPTION
        WHEN OTHERS THEN
            SYSTEM_LOG_EVENT(p_run_id, 'Scenario3 Mismatch Log failed: ' || SQLERRM, 3);
            RAISE;
    END GENERATE_SCENARIO3_MISMATCH_LOG;

    -- ----------------------------------------------------------------
    --  SEND_EMAIL_WITH_CLOBS
    --  Inner procedure: STREAM_CLOB_AS_ATTACHMENT
    -- ----------------------------------------------------------------
    PROCEDURE SEND_EMAIL_WITH_CLOBS (
        p_sender      IN VARCHAR2,
        p_recipient   IN VARCHAR2,
        p_cc          IN VARCHAR2,
        p_subject     IN VARCHAR2,
        p_message     IN VARCHAR2,
        p_file1_name  IN VARCHAR2,
        p_file1_clob  IN CLOB,
        p_file2_name  IN VARCHAR2,
        p_file2_clob  IN CLOB,
        p_file3_name  IN VARCHAR2,
        p_file3_clob  IN CLOB,
        p_file4_name  IN VARCHAR2,
        p_file4_clob  IN CLOB
    ) IS
        conn     UTL_SMTP.connection;
        boundary CONSTANT VARCHAR2(50) := '----=_NextPart_001';

        -- Inner procedure: stream one CLOB as a MIME attachment
        PROCEDURE STREAM_CLOB_AS_ATTACHMENT (
            p_name IN VARCHAR2,
            p_clob IN CLOB
        ) IS
            v_pos    INTEGER := 1;
            v_length INTEGER;
            v_chunk  VARCHAR2(10900);
        BEGIN
            IF p_clob IS NOT NULL THEN
                UTL_SMTP.write_data(conn,
                    '--' || boundary || CHR(13) || CHR(10) ||
                    'Content-Type: text/xml; name="' || p_name || '"' || CHR(13) || CHR(10) ||
                    'Content-Disposition: attachment; filename="' || p_name || '"' || CHR(13) || CHR(10) ||
                    CHR(13) || CHR(10)
                );

                v_length := DBMS_LOB.getlength(p_clob);
                WHILE v_pos <= v_length LOOP
                    v_chunk := DBMS_LOB.substr(p_clob, 10900, v_pos);
                    UTL_SMTP.write_data(conn, v_chunk);
                    v_pos := v_pos + 10900;
                END LOOP;

                UTL_SMTP.write_data(conn, CHR(13) || CHR(10));
            END IF;
        END STREAM_CLOB_AS_ATTACHMENT;

    BEGIN
        conn := UTL_SMTP.open_connection('localhost', 25);
        UTL_SMTP.helo(conn, 'localhost');
        UTL_SMTP.mail(conn, p_sender);
        UTL_SMTP.rcpt(conn, p_recipient);
        IF p_cc IS NOT NULL THEN
            UTL_SMTP.rcpt(conn, p_cc);
        END IF;

        UTL_SMTP.open_data(conn);
        UTL_SMTP.write_data(conn,
            'From: '    || p_sender    || CHR(13) || CHR(10) ||
            'To: '      || p_recipient || CHR(13) || CHR(10) ||
            'Cc: '      || p_cc        || CHR(13) || CHR(10) ||
            'Subject: ' || p_subject   || CHR(13) || CHR(10) ||
            'MIME-Version: 1.0'        || CHR(13) || CHR(10) ||
            'Content-Type: multipart/mixed; boundary="' || boundary || '"' || CHR(13) || CHR(10) ||
            CHR(13) || CHR(10)
        );

        -- Plain-text body
        UTL_SMTP.write_data(conn,
            '--' || boundary        || CHR(13) || CHR(10) ||
            'Content-Type: text/plain' || CHR(13) || CHR(10) ||
            CHR(13) || CHR(10) ||
            p_message               || CHR(13) || CHR(10)
        );

        -- Four attachments
        STREAM_CLOB_AS_ATTACHMENT(p_file1_name, p_file1_clob);
        STREAM_CLOB_AS_ATTACHMENT(p_file2_name, p_file2_clob);
        STREAM_CLOB_AS_ATTACHMENT(p_file3_name, p_file3_clob);
        STREAM_CLOB_AS_ATTACHMENT(p_file4_name, p_file4_clob);

        UTL_SMTP.write_data(conn, '--' || boundary || '--' || CHR(13) || CHR(10));
        UTL_SMTP.close_data(conn);
        UTL_SMTP.quit(conn);
    END SEND_EMAIL_WITH_CLOBS;

    -- ----------------------------------------------------------------
    --  PURGE_RECONCILIATION_LOGS
    -- ----------------------------------------------------------------
    PROCEDURE PURGE_RECONCILIATION_LOGS IS
        v_days_to_delete NUMBER;
        v_audit_deleted  NUMBER;
        v_file_deleted   NUMBER;
    BEGIN
        SELECT days_to_delete_auditlogs
        INTO v_days_to_delete
        FROM "system_configuration"
        WHERE is_active = 'Y'
        ORDER BY created_at DESC
        FETCH FIRST 1 ROWS ONLY;

        IF v_days_to_delete IS NULL THEN
            RETURN;
        END IF;

        DELETE FROM "system_log"
        WHERE created_at < SYSDATE - v_days_to_delete;
        v_audit_deleted := SQL%ROWCOUNT;

        DELETE FROM "generated_file"
        WHERE created_at < SYSDATE - v_days_to_delete;
        v_file_deleted := SQL%ROWCOUNT;

        COMMIT;

        SYSTEM_LOG_EVENT(
            NULL,
            'Log purge: deleted logs older than ' || v_days_to_delete || ' days'
            || ' (audit_logs: ' || v_audit_deleted || ' rows, file_logs: ' || v_file_deleted || ' rows)',
            1
        );

    EXCEPTION
        WHEN OTHERS THEN
            ROLLBACK;
            RAISE;
    END PURGE_RECONCILIATION_LOGS;

    -- ----------------------------------------------------------------
    --  TOGGLE_PURGE_JOB
    -- ----------------------------------------------------------------
    PROCEDURE TOGGLE_PURGE_JOB (p_enable IN CHAR) IS
    BEGIN
        IF p_enable = 'Y' THEN
            DBMS_SCHEDULER.enable('PURGE_LOGS_JOB');
            SYSTEM_LOG_EVENT(NULL, 'Scheduler toggle: enabled PURGE_LOGS_JOB', 1);
        ELSE
            DBMS_SCHEDULER.disable('PURGE_LOGS_JOB');
            SYSTEM_LOG_EVENT(NULL, 'Scheduler toggle: disabled PURGE_LOGS_JOB', 1);
        END IF;
    END TOGGLE_PURGE_JOB;

    -- ----------------------------------------------------------------
    --  RUN_MAIN_RECONCILIATION_LOG
    -- ----------------------------------------------------------------
    PROCEDURE RUN_MAIN_RECONCILIATION_LOG (
        p_is_triggered   IN  BOOLEAN DEFAULT FALSE, -- TRUE if run triggered by scheduler, FALSE if manual (returns CLOBs)
        p_triggered_by   IN  VARCHAR2 DEFAULT 'Manually',
        p_out_file1_name OUT VARCHAR2,
        p_out_file1_clob OUT CLOB,
        p_out_file2_name OUT VARCHAR2,
        p_out_file2_clob OUT CLOB,
        p_out_file3_name OUT VARCHAR2,
        p_out_file3_clob OUT CLOB,
        p_out_file4_name OUT VARCHAR2,
        p_out_file4_clob OUT CLOB
    ) IS
        v_run_id              NUMBER;
        v_config_id           NUMBER;
        v_missing_customer    NUMBER;
        v_missing_billing     NUMBER;
        v_mismatch_count      NUMBER;
        v_total_discrepancies NUMBER;
        v_total_records       NUMBER;
        v_recipients          VARCHAR2(4000);

        v_file_name1 VARCHAR2(200);  v_file_clob1 CLOB;
        v_file_name2 VARCHAR2(200);  v_file_clob2 CLOB;
        v_file_name3 VARCHAR2(200);  v_file_clob3 CLOB;
        v_file_name4 VARCHAR2(200);  v_file_clob4 CLOB;
    BEGIN
        -- Fetch latest active configuration
        SELECT config_id, email_recipients
        INTO v_config_id, v_recipients
        FROM "system_configuration"
        WHERE is_active = 'Y'
        ORDER BY created_at DESC
        FETCH FIRST 1 ROWS ONLY;

        -- Register run start
        REGISTER_RECONCILIATION_RUN(
            v_config_id,
            NULL,
            CASE WHEN p_is_triggered THEN 'Automatically' ELSE p_triggered_by END,
            CASE WHEN p_is_triggered THEN 1 ELSE 2 END,
            NULL,
            1,      -- Started
            v_run_id
        );
        SYSTEM_LOG_EVENT(v_run_id, 'Reconciliation run started', 1);

        -- Total records in scope
        SELECT COUNT(*) INTO v_total_records
        FROM (
            SELECT BNET_REF FROM Siebel_Table
            UNION ALL
            SELECT BNET_REF FROM ROWB_Table
        );

        -- Run all scenarios
        GENERATE_SCENARIO1_STEP1_LOG(
            v_missing_customer, v_file_name1, v_file_clob1,
            v_config_id, p_is_triggered, v_run_id
        );

        GENERATE_SCENARIO1_STEP2_LOG(
            v_file_name2, v_file_clob2,
            v_config_id, p_is_triggered, v_run_id
        );

        GENERATE_SCENARIO2_UPDATE_LOG(
            v_missing_billing, v_file_name3, v_file_clob3,
            v_config_id, p_is_triggered, v_run_id
        );

        GENERATE_SCENARIO3_MISMATCH_LOG(
            v_mismatch_count, v_file_name4, v_file_clob4,
            v_config_id, p_is_triggered, v_run_id
        );

        v_total_discrepancies := v_missing_customer + v_missing_billing + v_mismatch_count;

        REGISTER_RECONCILIATION_SUMMARY(
            v_total_records,
            v_total_discrepancies,
            v_mismatch_count,
            v_missing_customer,
            v_missing_billing,
            v_run_id
        );

        UPDATE_RECONCILIATION_RUN(v_run_id, 'Completed');

        IF p_is_triggered THEN
            IF v_recipients IS NOT NULL AND TRIM(v_recipients) IS NOT NULL THEN
                BEGIN
                    SEND_EMAIL_WITH_CLOBS(
                        p_sender     => 'noreply@test.local',
                        p_recipient  => v_recipients,
                        p_cc         => 'ccperson@test.local',
                        p_subject    => 'Reconciliation Run Results',
                        p_message    => 'Please find attached the reconciliation files generated for the process between Siebel and ROWB.<br><br>' ||
                                        'Each file corresponds to a specific scenario:<br>' ||
                                        '<ul>' ||
                                        '<li><b>SC1-Step1:</b> Missing records in ROWB compared to Siebel. [insert process]</li>' ||
                                        '<li><b>SC1-Step2:</b> Product linking in ROWB for new records in SC1-Step1. [insert process]</li>' ||
                                        '<li><b>SC2:</b> Package mismatches between Siebel and ROWB. [update process]</li>' ||
                                        '<li><b>SC3:</b> Billing discrepancies identified during reconciliation. [update process]</li>' ||
                                        '</ul>',
                        p_file1_name => v_file_name1,
                        p_file1_clob => v_file_clob1,
                        p_file2_name => v_file_name2,
                        p_file2_clob => v_file_clob2,
                        p_file3_name => v_file_name3,
                        p_file3_clob => v_file_clob3,
                        p_file4_name => v_file_name4,
                        p_file4_clob => v_file_clob4
                    );
                    SYSTEM_LOG_EVENT(v_run_id, 'Email with reconciliation results sent successfully', 1);
                    UPDATE_RECONCILIATION_RUN(v_run_id, 'Completed', NULL, 1);  -- email SENT
                EXCEPTION
                    WHEN OTHERS THEN
                        UPDATE_RECONCILIATION_RUN(v_run_id, 'Completed', SQLERRM, 2); -- email FAILED
                        SYSTEM_LOG_EVENT(v_run_id, 'Email sending failed: ' || SQLERRM, 2);
                END;
            ELSE
                SYSTEM_LOG_EVENT(v_run_id,
                    'Email skipped: no recipients configured in active configuration', 2);
                UPDATE_RECONCILIATION_RUN(v_run_id, 'Completed', NULL, NULL);
            END IF;
        ELSE
            -- Manual run – return CLOBs to caller
            p_out_file1_name := v_file_name1;  p_out_file1_clob := v_file_clob1;
            p_out_file2_name := v_file_name2;  p_out_file2_clob := v_file_clob2;
            p_out_file3_name := v_file_name3;  p_out_file3_clob := v_file_clob3;
            p_out_file4_name := v_file_name4;  p_out_file4_clob := v_file_clob4;
            SYSTEM_LOG_EVENT(v_run_id, 'Files returned to caller for manual run', 1);
            UPDATE_RECONCILIATION_RUN(v_run_id, 'Completed', NULL, NULL);
        END IF;

    EXCEPTION
        WHEN OTHERS THEN
            UPDATE_RECONCILIATION_RUN(v_run_id, 'Failed', SQLERRM, 2);
            SYSTEM_LOG_EVENT(v_run_id, 'Reconciliation run failed: ' || SQLERRM, 3);
            RAISE;
    END RUN_MAIN_RECONCILIATION_LOG;

END RECONCILIATION_LOG_PACKAGE;

