    FUNCTION  MAKE_CELL_NUMBER         (p_val      IN NUMBER)                            RETURN VARCHAR2;
    FUNCTION  MAKE_CELL_STRING         (p_val      IN VARCHAR2)                          RETURN VARCHAR2;
    FUNCTION  NORMALIZE_DATE           (p_val      IN VARCHAR2)                          RETURN TIMESTAMP;

    -- XML template builders
    PROCEDURE GENERATE_TEMPLATE_CLOB           (p_xml OUT CLOB);
    PROCEDURE GENERATE_BANDWIDTH_TEMPLATE_CLOB (p_xml OUT CLOB);

    -- XML row appenders
    PROCEDURE APPEND_ROW_TO_CLOB (
        p_xml             IN OUT CLOB,
        p_reference       IN     VARCHAR2,
        p_completion_date IN     TIMESTAMP,
        p_product         IN     VARCHAR2,
        p_starting_from   IN     TIMESTAMP
    );
    PROCEDURE APPEND_ROW_TO_BANDWIDTH_CLOB (
        p_xml             IN OUT CLOB,
        p_reference       IN     VARCHAR2,
        p_product_name    IN     VARCHAR2,
        p_rating_property IN     VARCHAR2,
        p_package_code    IN     VARCHAR2,
        p_effective_date  IN     TIMESTAMP
    );


    -- ================================================================
    --  PRIVATE IMPLEMENTATIONS
    -- ================================================================
    FUNCTION "ESCAPE_XML" (p_text IN VARCHAR2) RETURN VARCHAR2 IS
    BEGIN
        RETURN REPLACE(
                 REPLACE(
                   REPLACE(
                     REPLACE(p_text, '&', '&amp;'),
                   '<', '&lt;'),
                 '>', '&gt;'),
               '"', '&quot;');
    END "ESCAPE_XML";

    ------------------------------------------------------------
    -- FUNCTION: MAKE_CELL_DATETIME
    ------------------------------------------------------------
    FUNCTION "MAKE_CELL_DATETIME" (
        p_val      TIMESTAMP,
        p_style_id VARCHAR2
    ) RETURN VARCHAR2 IS
    BEGIN
        RETURN '<Cell ss:StyleID="' || p_style_id || '"><Data ss:Type="DateTime">' ||
               TO_CHAR(p_val, 'YYYY-MM-DD"T"HH24:MI:SS.FF3') ||
               '</Data></Cell>';
    END "MAKE_CELL_DATETIME";

    ------------------------------------------------------------
    -- FUNCTION: MAKE_CELL_NUMBER
    ------------------------------------------------------------
    FUNCTION "MAKE_CELL_NUMBER" (p_val NUMBER) RETURN VARCHAR2 IS
    BEGIN
        RETURN '<Cell><Data ss:Type="Number">' || p_val || '</Data></Cell>';
    END "MAKE_CELL_NUMBER";

    ------------------------------------------------------------
    -- FUNCTION: MAKE_CELL_STRING
    ------------------------------------------------------------
    FUNCTION "MAKE_CELL_STRING" (p_val VARCHAR2) RETURN VARCHAR2 IS
    BEGIN
        RETURN '<Cell><Data ss:Type="String">' || ESCAPE_XML(p_val) || '</Data></Cell>';
    END "MAKE_CELL_STRING";

    ------------------------------------------------------------
    -- FUNCTION: NORMALIZE_DATE
    ------------------------------------------------------------
    FUNCTION "NORMALIZE_DATE" (p_val VARCHAR2) RETURN TIMESTAMP IS
        v_ts TIMESTAMP;
    BEGIN
        BEGIN
            v_ts := TO_TIMESTAMP(p_val, 'MM/DD/YYYY HH24:MI');
            RETURN v_ts;
        EXCEPTION WHEN OTHERS THEN NULL;
        END;

        BEGIN
            v_ts := TO_TIMESTAMP(p_val, 'MM/DD/YYYY');
            RETURN v_ts;
        EXCEPTION WHEN OTHERS THEN NULL;
        END;

        RETURN NULL;
    END "NORMALIZE_DATE";

    ------------------------------------------------------------
    -- PROCEDURE: GENERATE_TEMPLATE_CLOB
