    ------------------------------------------------------------
    -- PROCEDURE: APPEND_ROW_TO_CLOB
    ------------------------------------------------------------
    PROCEDURE "APPEND_ROW_TO_CLOB" (
        p_xml             IN OUT CLOB,
        p_reference       IN VARCHAR2,
        p_completion_date IN TIMESTAMP,
        p_product         IN VARCHAR2,
        p_starting_from   IN TIMESTAMP
    ) IS
        v_row CLOB;
    BEGIN
        DBMS_LOB.CREATETEMPORARY(v_row, TRUE);

        DBMS_LOB.APPEND(v_row, '<Row>');
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('A'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('AGR_BRE_FR'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('Batelco National'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('Batelco'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(p_reference));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_DATETIME(p_completion_date, 's69'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(p_product));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('BHD'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('NEW'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(p_reference));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(p_reference));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('Description'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('DATE'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_DATETIME(p_starting_from, 's69'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_DATETIME(p_starting_from, 's69'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('STD'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_NUMBER(1));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('MONTH'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('SECOND'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('P'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('DYNAMIC'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('C'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('C'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('C'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('S'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_NUMBER(-1));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('HOUR'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('S'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_NUMBER(-1));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('HOUR'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('NO'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('NO'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_NUMBER(100));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, '</Row>' || CHR(10));

        DBMS_LOB.APPEND(p_xml, v_row);
    END "APPEND_ROW_TO_CLOB";

    ------------------------------------------------------------
    -- PROCEDURE: APPEND_ROW_TO_BANDWIDTH_CLOB
    ------------------------------------------------------------
    PROCEDURE "APPEND_ROW_TO_BANDWIDTH_CLOB" (
        p_xml             IN OUT CLOB,
        p_reference       IN VARCHAR2,
        p_product_name    IN VARCHAR2,
        p_rating_property IN VARCHAR2,
        p_package_code    IN VARCHAR2,
        p_effective_date  IN TIMESTAMP
    ) IS
        v_row CLOB;
    BEGIN
        DBMS_LOB.CREATETEMPORARY(v_row, TRUE);

        DBMS_LOB.APPEND(v_row, '<Row>');
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('A'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('AGR_BRE_FR'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('Batelco National'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('Batelco'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(p_reference));

        -- conditionally mapped product name
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(p_product_name));
        -- conditionally mapped rating property
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(p_rating_property));

        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING('BANDWIDTH'));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));

        -- effective date: first date of the month
        DBMS_LOB.APPEND(v_row, MAKE_CELL_DATETIME(p_effective_date, 's67'));

        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));

        -- package code from BNET_PACK_CODE column
        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(p_package_code));

        DBMS_LOB.APPEND(v_row, MAKE_CELL_STRING(''));
        DBMS_LOB.APPEND(v_row, '</Row>' || CHR(10));

        DBMS_LOB.APPEND(p_xml, v_row);
    END "APPEND_ROW_TO_BANDWIDTH_CLOB";

    ------------------------------------------------------------
    -- PROCEDURE: GENERATE_SCENARIO1_STEP1
    ------------------------------------------------------------
    PROCEDURE "GENERATE_SCENARIO1_STEP1" (
        p_file_name OUT VARCHAR2,
        p_file_clob OUT CLOB
    ) IS
        v_xml        CLOB;
        v_timestamp1 TIMESTAMP;
        v_timestamp2 TIMESTAMP;
        v_product    VARCHAR2(20);
    BEGIN
        -- Step 1: create template
        GENERATE_TEMPLATE_CLOB(v_xml);

        -- Step 2: loop through discrepancies
        FOR rec IN (
            SELECT *
            FROM Siebel_Table s
            WHERE s.BNET_REF IN (
                SELECT BNET_REF
                FROM Siebel_Table
                WHERE STATUS_CD = 'Active'
                  AND RENTAL_PLAN NOT LIKE '%eFax%'
                  AND BNET_PACK_CODE IS NOT NULL
                  AND BNET_REF NOT LIKE '1182896926%'
                  AND BNET_REF NOT LIKE '000%'
                  AND BNET_REF NOT LIKE 'Skip%'
                MINUS
                SELECT DISTINCT r.BNET_REF
                FROM ROWB_Table r
                WHERE r.STATUS = 'Active'
            )
        )
        LOOP
            -- First timestamp: fixed far-future date
            v_timestamp1 := TO_TIMESTAMP('2999-12-01 23:59:59.000',
                                         'YYYY-MM-DD HH24:MI:SS.FF3');

            -- Second timestamp: start of current billing month
            v_timestamp2 := TRUNC(SYSDATE, 'MM');

            -- Conditional product mapping
            IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
                v_product := 'WS_RES';
            ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
                v_product := 'WS_NRS';
            ELSE
                v_product := rec.BNET_PACK_CODE;
            END IF;

            APPEND_ROW_TO_CLOB(
                v_xml,
                rec.BNET_REF,
                v_timestamp1,
                v_product,
                v_timestamp2
            );
        END LOOP;

        -- Step 3: finalize
        finalize_xml_clob(v_xml);

        -- Step 4: return file name and content
        p_file_name := 'SC1-STEP1.xml';
        p_file_clob := v_xml;
    END "GENERATE_SCENARIO1_STEP1";

    ------------------------------------------------------------
    -- PROCEDURE: GENERATE_SCENARIO1_STEP2
    ------------------------------------------------------------
    PROCEDURE "GENERATE_SCENARIO1_STEP2" (
        p_file_name OUT VARCHAR2,
        p_file_clob OUT CLOB
    ) IS
        v_xml             CLOB;
        v_timestamp       TIMESTAMP;
        v_product_name    VARCHAR2(120);
        v_rating_property VARCHAR2(120);
    BEGIN
        -- Step 1: create template
        GENERATE_BANDWIDTH_TEMPLATE_CLOB(v_xml);

        -- Step 2: loop through discrepancies
        FOR rec IN (
            SELECT *
            FROM Siebel_Table s
            WHERE s.BNET_REF IN (
                SELECT BNET_REF
                FROM Siebel_Table
                WHERE STATUS_CD = 'Active'
                  AND RENTAL_PLAN NOT LIKE '%eFax%'
                  AND BNET_PACK_CODE IS NOT NULL
                  AND BNET_REF NOT LIKE '1182896926%'
                  AND BNET_REF NOT LIKE '000%'
                  AND BNET_REF NOT LIKE 'Skip%'
                MINUS
                SELECT DISTINCT r.BNET_REF
                FROM ROWB_Table r
                WHERE r.STATUS = 'Active'
            )
        )
        LOOP
            -- Billing date: start of current billing month
            v_timestamp := TRUNC(SYSDATE, 'MM');

            -- Conditional product mapping
            IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
                v_product_name    := 'WS_RES Outpayment';
                v_rating_property := 'RP_WS_RS_O';
            ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
                v_product_name    := 'WS_NRS Outpayment';
                v_rating_property := 'RP_WS_NS_O';
            ELSE
                v_product_name    := rec.BNET_PACK_CODE;
                v_rating_property := NULL;
            END IF;

            APPEND_ROW_TO_BANDWIDTH_CLOB(
                v_xml,
                rec.BNET_REF,
                v_product_name,
                v_rating_property,
                rec.BNET_PACK_CODE,
                v_timestamp
            );
        END LOOP;

        -- Step 3: finalize
        finalize_xml_clob(v_xml);

        -- Step 4: return file name and content
        p_file_name := 'SC1-STEP2.xml';
        p_file_clob := v_xml;
    END "GENERATE_SCENARIO1_STEP2";

    ------------------------------------------------------------
    -- PROCEDURE: GENERATE_SCENARIO2_UPDATE
    ------------------------------------------------------------
    PROCEDURE "GENERATE_SCENARIO2_UPDATE" (
        p_file_name OUT VARCHAR2,
        p_file_clob OUT CLOB
    ) IS
        v_xml        CLOB;
        v_timestamp1 TIMESTAMP;
        v_timestamp2 TIMESTAMP;
        v_product    VARCHAR2(20);
    BEGIN
        -- Step 1: create template
        GENERATE_TEMPLATE_CLOB(v_xml);

        -- Step 2: loop through Scenario Two discrepancies
        FOR rec IN (
            SELECT r.BNET_REF,
                   s.BNET_PACK_CODE,
                   s.DISCONNECT_DT,
                   s.START_DT
            FROM ROWB_Table r
            LEFT JOIN Siebel_Table s
              ON r.BNET_REF = s.BNET_REF
            WHERE UPPER(r.STATUS) = 'ACTIVE'
              AND r.BNET_REF NOT LIKE '1182896926%'
              AND r.BNET_REF NOT LIKE '000%'
              AND r.BNET_REF NOT LIKE 'Skip%'
              AND r.BNET_REF IS NOT NULL
              AND r.BNET_REF NOT IN (
                  SELECT s2.BNET_REF
                  FROM Siebel_Table s2
                  WHERE UPPER(s2.STATUS_CD) <> 'ACTIVE'
                    AND s2.DISCONNECT_DT IS NOT NULL
                    AND s2.RENTAL_PLAN NOT LIKE '%eFax%'
                    AND s2.BNET_PACK_CODE IS NOT NULL
              )
        )
        LOOP
            -- Effective TO: normalize DISCONNECT_DT
            v_timestamp1 := NORMALIZE_DATE(rec.DISCONNECT_DT);

            -- Effective FROM: normalize START_DT
            v_timestamp2 := NORMALIZE_DATE(rec.START_DT);

            -- Conditional product mapping
            IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
                v_product := 'WS_RES';
            ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
                v_product := 'WS_NRS';
            ELSE
                v_product := rec.BNET_PACK_CODE;
            END IF;

            APPEND_ROW_TO_CLOB(
                v_xml,
                rec.BNET_REF,
                v_timestamp1,
                v_product,
                v_timestamp2
            );
        END LOOP;

        -- Step 3: finalize
        finalize_xml_clob(v_xml);

        -- Step 4: return file name and content
        p_file_name := 'SC2-UPDATE.xml';
        p_file_clob := v_xml;
    END "GENERATE_SCENARIO2_UPDATE";

    ------------------------------------------------------------
    -- PROCEDURE: GENERATE_SCENARIO3_MISMATCH
    ------------------------------------------------------------
    PROCEDURE "GENERATE_SCENARIO3_MISMATCH" (
        p_file_name OUT VARCHAR2,
        p_file_clob OUT CLOB
    ) IS
        v_xml             CLOB;
        v_timestamp       TIMESTAMP;
        v_product_name    VARCHAR2(120);
        v_rating_property VARCHAR2(120);
    BEGIN
        -- Step 1: create template
        GENERATE_BANDWIDTH_TEMPLATE_CLOB(v_xml);

        -- Step 2: loop through mismatched package discrepancies
        FOR rec IN (
            SELECT r.BNET_REF,
                   s.BNET_PACK_CODE
            FROM ROWB_Table r
            JOIN Siebel_Table s
              ON r.BNET_REF = s.BNET_REF
            WHERE r.ROWB_PACKAGE <> s.BNET_PACK_CODE
              AND s.BNET_PACK_CODE IS NOT NULL
              AND r.ROWB_PACKAGE IS NOT NULL
              AND s.RENTAL_PLAN NOT LIKE '%eFax%'
              AND r.BNET_REF NOT LIKE '1182896926%'
              AND r.BNET_REF NOT LIKE '000%'
              AND r.BNET_REF NOT LIKE 'Skip%'
        )
        LOOP
            -- Billing date: start of current billing month
            v_timestamp := TRUNC(SYSDATE, 'MM');

            -- Conditional product mapping based on Siebel pack code
            IF rec.BNET_PACK_CODE LIKE '%ESSENTIAL%' THEN
                v_product_name    := 'WS_RES Outpayment';
                v_rating_property := 'RP_WS_RS_O';
            ELSIF rec.BNET_PACK_CODE LIKE '%ADVANCED%' THEN
                v_product_name    := 'WS_NRS Outpayment';
                v_rating_property := 'RP_WS_NS_O';
            ELSE
                v_product_name    := rec.BNET_PACK_CODE;
                v_rating_property := NULL;
            END IF;

            APPEND_ROW_TO_BANDWIDTH_CLOB(
                v_xml,
                rec.BNET_REF,
                v_product_name,
                v_rating_property,
                rec.BNET_PACK_CODE,
                v_timestamp
            );
        END LOOP;

        -- Step 3: finalize
        finalize_xml_clob(v_xml);

        -- Step 4: return file name and content
        p_file_name := 'SC3-MISMATCH.xml';
        p_file_clob := v_xml;
    END "GENERATE_SCENARIO3_MISMATCH";

    ------------------------------------------------------------
    -- PROCEDURE: SEND_EMAIL_WITH_CLOBS
    ------------------------------------------------------------
    PROCEDURE SEND_EMAIL_WITH_CLOBS (
        p_sender      IN VARCHAR2,
        p_recipient   IN VARCHAR2,
        p_cc          IN VARCHAR2,
        p_subject     IN VARCHAR2,
        p_message     IN VARCHAR2,
        p_file1_name  IN VARCHAR2,
        p_file1_clob  IN CLOB,
        p_file2_name  IN VARCHAR2,
        p_file2_clob  IN CLOB,
        p_file3_name  IN VARCHAR2,
        p_file3_clob  IN CLOB,
        p_file4_name  IN VARCHAR2,
        p_file4_clob  IN CLOB
    ) IS
        conn     UTL_SMTP.connection;
        boundary CONSTANT VARCHAR2(50) := '----=_NextPart_001';

        -- Helper to stream CLOB safely in chunks
        PROCEDURE stream_clob_as_attachment (
            p_name IN VARCHAR2,
            p_clob IN CLOB
        ) IS
            v_pos    INTEGER := 1;
            v_length INTEGER;
            v_chunk  VARCHAR2(10900); -- safe chunk size
        BEGIN
            IF p_clob IS NOT NULL THEN
                -- Write attachment headers
                UTL_SMTP.write_data(conn,
                    '--' || boundary || CHR(13) || CHR(10) ||
                    'Content-Type: text/xml; name="' || p_name || '"' || CHR(13) || CHR(10) ||
                    'Content-Disposition: attachment; filename="' || p_name || '"' || CHR(13) || CHR(10) ||
                    CHR(13) || CHR(10)
                );

                -- Stream CLOB in chunks
                v_length := DBMS_LOB.getlength(p_clob);
                WHILE v_pos <= v_length LOOP
                    v_chunk := DBMS_LOB.substr(p_clob, 10900, v_pos);
                    UTL_SMTP.write_data(conn, v_chunk);
                    v_pos := v_pos + 10900;
                END LOOP;

                UTL_SMTP.write_data(conn, CHR(13) || CHR(10));
            END IF;
        END stream_clob_as_attachment;

    BEGIN
        -- Connect to smtp4dev (localhost:25)
        conn := UTL_SMTP.open_connection('localhost', 25);
        UTL_SMTP.helo(conn, 'localhost');
        UTL_SMTP.mail(conn, p_sender);
        UTL_SMTP.rcpt(conn, p_recipient);
        IF p_cc IS NOT NULL THEN
            UTL_SMTP.rcpt(conn, p_cc);
        END IF;

        -- Start email headers
        UTL_SMTP.open_data(conn);
        UTL_SMTP.write_data(conn,
            'From: ' || p_sender || CHR(13) || CHR(10) ||
            'To: ' || p_recipient || CHR(13) || CHR(10) ||
            'Cc: ' || p_cc || CHR(13) || CHR(10) ||
            'Subject: ' || p_subject || CHR(13) || CHR(10) ||
            'MIME-Version: 1.0' || CHR(13) || CHR(10) ||
            'Content-Type: multipart/mixed; boundary="' || boundary || '"' || CHR(13) || CHR(10) ||
            CHR(13) || CHR(10)
        );

        -- Body
        UTL_SMTP.write_data(conn,
            '--' || boundary || CHR(13) || CHR(10) ||
            'Content-Type: text/plain' || CHR(13) || CHR(10) ||
            CHR(13) || CHR(10) ||
            p_message || CHR(13) || CHR(10)
        );

        -- Attachments
        stream_clob_as_attachment(p_file1_name, p_file1_clob);
        stream_clob_as_attachment(p_file2_name, p_file2_clob);
        stream_clob_as_attachment(p_file3_name, p_file3_clob);
        stream_clob_as_attachment(p_file4_name, p_file4_clob);

        -- End boundary
        UTL_SMTP.write_data(conn, '--' || boundary || '--' || CHR(13) || CHR(10));

        UTL_SMTP.close_data(conn);
        UTL_SMTP.quit(conn);
    END SEND_EMAIL_WITH_CLOBS;

    ------------------------------------------------------------
    -- PROCEDURE: RUN_MAIN_RECONCILIATION
    ------------------------------------------------------------
    PROCEDURE RUN_MAIN_RECONCILIATION IS
        v_file1_name VARCHAR2(200);
        v_file1_clob CLOB;
        v_file2_name VARCHAR2(200);
        v_file2_clob CLOB;
        v_file3_name VARCHAR2(200);
        v_file3_clob CLOB;
        v_file4_name VARCHAR2(200);
        v_file4_clob CLOB;
    BEGIN
        -- Scenario 1 Step 1
        GENERATE_SCENARIO1_STEP1(v_file1_name, v_file1_clob);

        -- Scenario 1 Step 2
        GENERATE_SCENARIO1_STEP2(v_file2_name, v_file2_clob);

        -- Scenario 2 Update
        GENERATE_SCENARIO2_UPDATE(v_file3_name, v_file3_clob);

        -- Scenario 3 Mismatch
        GENERATE_SCENARIO3_MISMATCH(v_file4_name, v_file4_clob);

        -- Send email with all four attachments
        SEND_EMAIL_WITH_CLOBS(
            p_sender      => 'noreply@test.local',
            p_recipient   => 'receiver@test.local',
            p_cc          => 'ccperson@test.local',
            p_subject     => 'Reconciliation Run Results',
            p_message     => 'Please find attached the reconciliation files generated for the process between Siebel and ROWB.<br><br>' ||
                             'Each file corresponds to a specific scenario:<br>' ||
                             '<ul>' ||
                             '<li><b>SC1-Step1:</b> Missing records in ROWB compared to Siebel. [insert process]</li>' ||
                             '<li><b>SC1-Step2:</b> Product linking in ROWB for new records in SC1-Step1. [insert process]</li>' ||
                             '<li><b>SC2:</b> Package mismatches between Siebel and ROWB. [update process]</li>' ||
                             '<li><b>SC3:</b> Billing discrepancies identified during reconciliation. [update process]</li>' ||
                             '</ul>',
            p_file1_name  => v_file1_name,
            p_file1_clob  => v_file1_clob,
            p_file2_name  => v_file2_name,
            p_file2_clob  => v_file2_clob,
            p_file3_name  => v_file3_name,
            p_file3_clob  => v_file3_clob,
            p_file4_name  => v_file4_name,
            p_file4_clob  => v_file4_clob
        );
    END RUN_MAIN_RECONCILIATION;

END RECONCILIATION_PACKAGE;

/
--------------------------------------------------------
--  DDL for Function ESCAPE_XML
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE FUNCTION "BILLING_MOCK"."ESCAPE_XML" (p_text IN VARCHAR2) RETURN VARCHAR2 IS
BEGIN
    RETURN REPLACE(
             REPLACE(
               REPLACE(
                 REPLACE(p_text, '&', '&amp;'),
               '<', '&lt;'),
             '>', '&gt;'),
           '"', '&quot;');
END;


/
--------------------------------------------------------
--  DDL for Function MAKE_CELL_DATETIME
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE FUNCTION "BILLING_MOCK"."MAKE_CELL_DATETIME" (
    p_val      TIMESTAMP,
    p_style_id VARCHAR2
) RETURN VARCHAR2 IS
BEGIN
    RETURN '<Cell ss:StyleID="' || p_style_id || '"><Data ss:Type="DateTime">' ||
           TO_CHAR(p_val, 'YYYY-MM-DD"T"HH24:MI:SS.FF3') ||
           '</Data></Cell>';
END;


/
--------------------------------------------------------
--  DDL for Function MAKE_CELL_NUMBER
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE FUNCTION "BILLING_MOCK"."MAKE_CELL_NUMBER" (p_val NUMBER) RETURN VARCHAR2 IS
BEGIN
    RETURN '<Cell><Data ss:Type="Number">' || p_val || '</Data></Cell>';
END;


/
--------------------------------------------------------
--  DDL for Function MAKE_CELL_STRING
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE FUNCTION "BILLING_MOCK"."MAKE_CELL_STRING" (p_val VARCHAR2) RETURN VARCHAR2 IS
BEGIN
    RETURN '<Cell><Data ss:Type="String">' || escape_xml(p_val) || '</Data></Cell>';
END;


/
--------------------------------------------------------
--  DDL for Function NORMALIZE_DATE
--------------------------------------------------------

  CREATE OR REPLACE EDITIONABLE FUNCTION "BILLING_MOCK"."NORMALIZE_DATE" (p_val VARCHAR2)
RETURN TIMESTAMP IS
    v_ts TIMESTAMP;
BEGIN
    BEGIN
        -- Try full date + time
        v_ts := TO_TIMESTAMP(p_val, 'MM/DD/YYYY HH24:MI');
        RETURN v_ts;
    EXCEPTION WHEN OTHERS THEN NULL;
    END;

    BEGIN
        -- Try date only
        v_ts := TO_TIMESTAMP(p_val, 'MM/DD/YYYY');
        RETURN v_ts;
    EXCEPTION WHEN OTHERS THEN NULL;
    END;

    -- If nothing worked, return NULL
    RETURN NULL;
END;


